// ── Workflow Spec (parsed from YAML) ──

export interface WorkflowSpec {
  name: string;
  description: string;
  version?: string;
  input?: Record<string, unknown>;       // JSON Schema object
  output?: Record<string, unknown>;      // JSON Schema object
  triggerTurn?: boolean;                  // default: true
  steps: Record<string, StepSpec>;       // ordered (YAML preserves insertion order)
  // Set by discovery, not by YAML:
  source: "user" | "project";
  filePath: string;
}

export interface StepSpec {
  agent: string;                         // agent name (required in phase 1)
  model?: string;                        // model override
  input?: Record<string, unknown>;       // values may contain ${{ }} expressions
  output?: StepOutputSpec;
  // Phase 2+:
  when?: string;
  timeout?: { seconds: number };
  loop?: unknown;
  gate?: unknown;
  transform?: unknown;
  workflow?: string;
}

export interface StepOutputSpec {
  format?: "json" | "text";              // default: "text"
  schema?: string;                       // path to JSON Schema file, relative to workflow spec
}

// ── Agent Spec (loaded from .md frontmatter or .agent.yaml) ──

export interface AgentSpec {
  name: string;
  description?: string;
  systemPrompt?: string;
  model?: string;
  thinking?: string;
  tools?: string[];
  extensions?: string[];
  skills?: string[];
  output?: string;                       // output file path
}

// ── Execution State ──

export interface ExecutionState {
  input: unknown;
  steps: Record<string, StepResult>;
  status: "running" | "completed" | "failed";
}

export interface StepResult {
  step: string;
  agent: string;
  status: "completed" | "failed" | "skipped";
  output?: unknown;                      // parsed structured output (if schema-bound)
  textOutput?: string;                   // raw text from last assistant message
  sessionLog?: string;                   // path to session log file
  usage: StepUsage;
  durationMs: number;
  error?: string;                        // error message if failed
}

export interface StepUsage {
  input: number;
  output: number;
  cacheRead: number;
  cacheWrite: number;
  cost: number;
  turns: number;
}

// ── Workflow Result (returned to caller) ──

export interface WorkflowResult {
  workflow: string;
  runId: string;
  status: "completed" | "failed";
  steps: Record<string, StepResult>;
  output?: unknown;                      // final workflow output (last step's output, or explicit)
  totalUsage: StepUsage;
  totalDurationMs: number;
  runDir: string;                        // absolute path to .pi/workflow-runs/<run-id>/
}

// ── Expression Scope (what ${{ }} expressions resolve against) ──

export interface ExpressionScope {
  input: unknown;
  steps: Record<string, StepResult>;
}

import { parse as parseYaml } from "yaml";
import { discoverWorkflows, findWorkflow } from "./workflow-discovery.ts";
import { executeWorkflow } from "./workflow-executor.ts";
import type { AgentSpec, WorkflowResult } from "./types.ts";
import fs from "node:fs";
import path from "node:path";
import os from "node:os";

// ── Minimal type declarations for pi extension API ──────────────────────────
// The actual types come from @mariozechner/pi-coding-agent and @sinclair/typebox,
// which are peer dependencies that may not be resolvable at test time.
// We define minimal compatible interfaces here so this module can be imported
// without those packages installed.

let Type: any;
try {
  Type = (await import("@sinclair/typebox")).Type;
} catch {
  // typebox not available — provide a minimal shim for tests that import
  // this module but never exercise the extension factory.
  Type = {
    Object: (props: Record<string, unknown>) => ({ type: "object", properties: props }),
    String: (opts?: unknown) => ({ type: "string", ...(opts || {}) }),
    Optional: (schema: unknown) => schema,
    Unknown: (opts?: unknown) => ({ ...(opts || {}) }),
  };
}

// ── parseAgentFrontmatter ───────────────────────────────────────────────────

/**
 * Parse YAML frontmatter from a .md agent file.
 * Frontmatter is between --- markers at the start of the file.
 * Content after frontmatter is the system prompt.
 */
export function parseAgentFrontmatter(filePath: string): AgentSpec {
  const content = fs.readFileSync(filePath, "utf-8");
  const match = content.match(/^---\n([\s\S]*?)\n---\n?([\s\S]*)$/);

  if (!match) {
    return { name: path.basename(filePath, ".md") };
  }

  const frontmatter = parseYaml(match[1]);
  const systemPrompt = match[2].trim();

  return {
    name: frontmatter.name || path.basename(filePath, ".md"),
    description: frontmatter.description,
    model: frontmatter.model,
    thinking: frontmatter.thinking,
    tools: frontmatter.tools,
    extensions: frontmatter.extensions,
    skills: frontmatter.skills,
    output: frontmatter.output,
    systemPrompt: systemPrompt || undefined,
  };
}

// ── Agent loader factory ────────────────────────────────────────────────────

export function createAgentLoader(cwd: string): (name: string) => AgentSpec {
  return (name: string): AgentSpec => {
    const searchPaths = [
      path.join(cwd, ".pi", "agents", `${name}.md`),
      path.join(os.homedir(), ".pi", "agent", "agents", `${name}.md`),
    ];

    for (const agentPath of searchPaths) {
      if (fs.existsSync(agentPath)) {
        return parseAgentFrontmatter(agentPath);
      }
    }

    return { name };
  };
}

// ── Helper functions ────────────────────────────────────────────────────────

function listWorkflowNames(cwd: string): string {
  const workflows = discoverWorkflows(cwd);
  if (workflows.length === 0) return "(none)";
  return workflows.map((w) => w.name).join(", ");
}

/**
 * Summarize a JSON Schema's expected shape for error messages.
 * Produces something like: { path: string (required), question?: string }
 */
function summarizeInputSchema(schema: Record<string, unknown> | undefined): string {
  if (!schema) return "(any)";
  const props = schema.properties as Record<string, any> | undefined;
  if (!props) return JSON.stringify(schema);
  const required = new Set(Array.isArray(schema.required) ? schema.required : []);
  const fields = Object.entries(props).map(([key, val]) => {
    const type = val?.type || "unknown";
    const req = required.has(key);
    return req ? `${key}: ${type} (required)` : `${key}?: ${type}`;
  });
  return `{ ${fields.join(", ")} }`;
}

function formatToolResult(result: WorkflowResult): string {
  const status = result.status === "completed" ? "completed" : "failed";
  const stepSummary = Object.entries(result.steps)
    .map(([name, s]) => `${s.status === "completed" ? "\u2713" : "\u2717"} ${name}`)
    .join(", ");
  return `Workflow '${result.workflow}' ${status}: ${stepSummary}. Run dir: ${result.runDir}`;
}

// ── Command handlers ────────────────────────────────────────────────────────

async function handleList(ctx: any): Promise<void> {
  const workflows = discoverWorkflows(ctx.cwd);
  if (workflows.length === 0) {
    ctx.ui.notify("No workflows found in .pi/workflows/ or ~/.pi/agent/workflows/", "info");
    return;
  }

  const lines = workflows.map((w) => {
    const source = w.source === "project" ? "[project]" : "[user]";
    const desc = w.description ? ` \u2014 ${w.description}` : "";
    return `  ${w.name} ${source}${desc}`;
  });
  ctx.ui.notify(`Available workflows:\n${lines.join("\n")}`, "info");
}

async function handleRun(rawArgs: string, ctx: any, pi: any): Promise<void> {
  // Extract workflow name (first token) and --input value (everything after --input flag)
  const inputFlagIdx = rawArgs.indexOf("--input");
  let namePart: string;
  let inputJson: string | undefined;

  if (inputFlagIdx !== -1) {
    namePart = rawArgs.slice(0, inputFlagIdx).trim();
    inputJson = rawArgs.slice(inputFlagIdx + "--input".length).trim();
    // Strip surrounding single or double quotes
    if ((inputJson.startsWith("'") && inputJson.endsWith("'")) ||
        (inputJson.startsWith('"') && inputJson.endsWith('"'))) {
      inputJson = inputJson.slice(1, -1);
    }
  } else {
    namePart = rawArgs.trim();
  }

  const name = namePart.split(/\s+/)[0];
  if (!name) {
    ctx.ui.notify("Usage: /workflow run <name> [--input '<json>']", "warning");
    return;
  }

  const spec = findWorkflow(name, ctx.cwd);
  if (!spec) {
    ctx.ui.notify(`Workflow '${name}' not found.`, "warning");
    return;
  }

  // Parse --input if provided
  let input: unknown = {};
  if (inputJson) {
    try {
      input = JSON.parse(inputJson);
    } catch {
      ctx.ui.notify(`Invalid JSON for --input: ${inputJson}`, "warning");
      return;
    }
  }

  try {
    await executeWorkflow(spec, input, {
      ctx,
      pi,
      loadAgent: createAgentLoader(ctx.cwd),
    });
    // Result is injected into conversation by executeWorkflow via sendMessage
  } catch (err) {
    ctx.ui.notify(
      `Workflow '${name}' failed: ${err instanceof Error ? err.message : String(err)}`,
      "error",
    );
  }
}

// ── Extension factory ───────────────────────────────────────────────────────

const extension = (pi: any) => {
  // ── Tool: workflow ──────────────────────────────────────────────────────

  pi.registerTool({
    name: "workflow",
    label: "Workflow",
    description: "Run a named workflow with typed input. Discovers workflows from .pi/workflows/ and ~/.pi/agent/workflows/.",
    promptSnippet: "Run a multi-step workflow with typed data flow between agents",
    parameters: Type.Object({
      workflow: Type.String({ description: "Name of the workflow to run" }),
      input: Type.Optional(Type.Unknown({ description: "Input data for the workflow (validated against workflow's input schema)" })),
    }),

    async execute(toolCallId: string, params: any, signal: AbortSignal, onUpdate: any, ctx: any) {
      const spec = findWorkflow(params.workflow, ctx.cwd);
      if (!spec) {
        return {
          content: [{ type: "text", text: `Workflow '${params.workflow}' not found. Available workflows: ${listWorkflowNames(ctx.cwd)}` }],
          details: undefined,
        };
      }

      // Defensive: if input arrives as a JSON string (e.g. from Type.Unknown()),
      // parse it into an object.
      let input = params.input ?? {};
      if (typeof input === "string") {
        try {
          input = JSON.parse(input);
        } catch {
          // leave as string — validation will catch it if schema expects object
        }
      }

      try {
        const result = await executeWorkflow(spec, input, {
          ctx,
          pi,
          signal,
          loadAgent: createAgentLoader(ctx.cwd),
        });

        return {
          content: [{ type: "text", text: formatToolResult(result) }],
          details: result,
        };
      } catch (err) {
        const errMsg = err instanceof Error ? err.message : String(err);
        const schemaHint = spec.input ? `\nExpected input: ${summarizeInputSchema(spec.input)}` : "";
        return {
          content: [{ type: "text", text: `Workflow '${params.workflow}' failed: ${errMsg}${schemaHint}` }],
          details: undefined,
        };
      }
    },
  });

  // ── Command: /workflow ──────────────────────────────────────────────────

  pi.registerCommand("workflow", {
    description: "List and run workflows",
    getArgumentCompletions: (prefix: string) => {
      const subcommands = ["run", "list", "status"];
      return subcommands
        .filter((s) => s.startsWith(prefix))
        .map((s) => ({ value: s, label: s }));
    },

    async handler(args: string, ctx: any) {
      const trimmed = args.trim();
      const spaceIdx = trimmed.indexOf(" ");
      const subcommand = spaceIdx === -1 ? trimmed || "list" : trimmed.slice(0, spaceIdx);
      const rest = spaceIdx === -1 ? "" : trimmed.slice(spaceIdx + 1);

      if (subcommand === "list") {
        await handleList(ctx);
      } else if (subcommand === "run") {
        await handleRun(rest, ctx, pi);
      } else if (subcommand === "status") {
        ctx.ui.notify("No workflow currently running.", "info");
      } else {
        ctx.ui.notify(`Unknown subcommand: ${subcommand}. Use: list, run, status`, "warning");
      }
    },
  });
};

export default extension;

import type { ExpressionScope, StepResult } from "./types.ts";

const EXPR_PATTERN = /\$\{\{\s*(.*?)\s*\}\}/g;

/**
 * Error class for expression resolution failures.
 * Contains the original expression and a diagnostic reason.
 */
export class ExpressionError extends Error {
  readonly expression: string;
  readonly reason: string;

  constructor(expression: string, reason: string) {
    super(`Expression error in '\${{ ${expression} }}': ${reason}`);
    this.name = "ExpressionError";
    this.expression = expression;
    this.reason = reason;
  }
}

/**
 * Resolve a single expression string (without the ${{ }} delimiters).
 * E.g. "steps.diagnose.output.rootCause" walks scope.steps.diagnose.output.rootCause
 *
 * Throws ExpressionError if any segment of the path is undefined or null.
 */
export function resolveExpression(expr: string, scope: ExpressionScope): unknown {
  const segments = expr.split(".");
  let current: unknown = scope;
  const traversed: string[] = [];

  for (const segment of segments) {
    // Container is undefined/null — can't traverse further. This is a broken reference.
    if (current === undefined || current === null) {
      const reason = buildErrorReason(segments, traversed, scope);
      throw new ExpressionError(expr, reason);
    }

    current = (current as Record<string, unknown>)[segment];
    traversed.push(segment);

    // Property doesn't exist on the container — return undefined (optional field).
    // But if this is the first segment (root lookup like "steps" or "input"),
    // or if we're looking up a step name that hasn't executed, that's an error.
    if (current === undefined) {
      // Root-level miss (e.g. "typo.something") — always an error
      if (traversed.length === 1) {
        const reason = buildErrorReason(segments, traversed, scope);
        throw new ExpressionError(expr, reason);
      }
      // Step reference that doesn't exist (e.g. "steps.nonexistent") — error
      if (segments[0] === "steps" && traversed.length === 2) {
        const reason = buildErrorReason(segments, traversed, scope);
        throw new ExpressionError(expr, reason);
      }
      // Otherwise: optional field on an existing object — return undefined
      return undefined;
    }
  }

  return current;
}

/**
 * Resolve all ${{ }} expressions in a value.
 *
 * - If `value` is a string containing `${{ expr }}`, resolve the expression.
 * - If `value` is a string that IS entirely `${{ expr }}`, return the resolved value
 *   (preserving its type -- object, array, number, etc.).
 * - If `value` is a string with `${{ expr }}` embedded in other text,
 *   stringify the resolved value and interpolate.
 * - If `value` is an object, recursively resolve all values.
 * - If `value` is an array, recursively resolve all elements.
 * - If `value` is anything else (number, boolean, null), return as-is.
 *
 * Throws ExpressionError if a property path doesn't resolve.
 */
export function resolveExpressions(value: unknown, scope: ExpressionScope): unknown {
  if (typeof value === "string") {
    return resolveStringExpressions(value, scope);
  }

  if (Array.isArray(value)) {
    return value.map((element) => resolveExpressions(element, scope));
  }

  if (value !== null && typeof value === "object") {
    const result: Record<string, unknown> = {};
    for (const [key, val] of Object.entries(value as Record<string, unknown>)) {
      result[key] = resolveExpressions(val, scope);
    }
    return result;
  }

  // number, boolean, null, undefined — pass through
  return value;
}

/**
 * Resolve expressions within a string value.
 * Handles whole-value expressions (type-preserving) and embedded expressions (string interpolation).
 */
function resolveStringExpressions(value: string, scope: ExpressionScope): unknown {
  // Check if the entire string is a single whole-value expression
  const wholeMatch = value.match(/^\$\{\{\s*(.*?)\s*\}\}$/);
  if (wholeMatch) {
    return resolveExpression(wholeMatch[1], scope);
  }

  // Check if there are any expressions at all
  if (!value.includes("${{")) {
    return value;
  }

  // Embedded expressions: resolve each and interpolate as strings
  return value.replace(EXPR_PATTERN, (_match, expr: string) => {
    const resolved = resolveExpression(expr, scope);
    if (resolved === undefined || resolved === null) return "";
    return stringify(resolved);
  });
}

/**
 * Stringify a resolved value for embedding in a larger string.
 * Objects and arrays use JSON.stringify; primitives use String().
 */
function stringify(value: unknown): string {
  if (value !== null && typeof value === "object") {
    return JSON.stringify(value);
  }
  return String(value);
}

/**
 * Build a diagnostic error reason based on the path traversal state.
 * Provides context about step status when the path starts with "steps.".
 */
function buildErrorReason(
  segments: string[],
  traversed: string[],
  scope: ExpressionScope,
): string {
  const failedSegment = traversed[traversed.length - 1];
  const parentPath = traversed.slice(0, -1).join(".");

  // Special case: referencing a step that doesn't exist in scope.steps
  if (segments[0] === "steps" && traversed.length === 2) {
    const stepName = segments[1];
    const stepsObj = scope.steps as Record<string, StepResult | undefined>;
    if (!(stepName in stepsObj)) {
      return `step '${stepName}' has not been executed yet`;
    }
  }

  // When the path starts with "steps.", include step status context if available
  if (segments[0] === "steps" && segments.length >= 2) {
    const stepName = segments[1];
    const stepsObj = scope.steps as Record<string, StepResult | undefined>;
    const stepResult = stepsObj[stepName];
    if (stepResult && parentPath) {
      return `property '${failedSegment}' is undefined on ${parentPath} (step '${stepName}' status: ${stepResult.status})`;
    }
  }

  if (parentPath) {
    return `property '${failedSegment}' is undefined on ${parentPath}`;
  }

  return `property '${failedSegment}' is undefined`;
}

import Ajv from "ajv";
import type { ErrorObject } from "ajv";
import fs from "node:fs";

const ajv = new Ajv({ allErrors: true, strict: false });

/**
 * Error class for validation failures.
 * Contains the original AJV errors and a formatted message.
 */
export class ValidationError extends Error {
  readonly label: string;
  readonly errors: ErrorObject[];

  constructor(label: string, errors: ErrorObject[]) {
    const details = errors
      .map((e) => `${e.instancePath || ""}: ${e.message}`)
      .join("; ");
    super(`Validation failed for ${label}: ${details}`);
    this.name = "ValidationError";
    this.label = label;
    this.errors = errors;
  }
}

/**
 * Validate data against a JSON Schema object.
 * Throws ValidationError with formatted error messages on failure.
 * Returns the validated data on success (pass-through).
 */
export function validate(schema: Record<string, unknown>, data: unknown, label: string): unknown {
  const valid = ajv.validate(schema, data);
  if (!valid) {
    throw new ValidationError(label, ajv.errors ?? []);
  }
  return data;
}

/**
 * Load a JSON Schema from a file path and validate data against it.
 * Throws if the schema file doesn't exist or is invalid JSON.
 * Throws ValidationError on validation failure.
 */
export function validateFromFile(schemaPath: string, data: unknown, label: string): unknown {
  let content: string;
  try {
    content = fs.readFileSync(schemaPath, "utf-8");
  } catch {
    throw new Error(`Schema file not found: ${schemaPath}`);
  }

  let schema: Record<string, unknown>;
  try {
    schema = JSON.parse(content);
  } catch (err) {
    throw new Error(
      `Invalid JSON in schema file: ${schemaPath}: ${err instanceof Error ? err.message : String(err)}`,
    );
  }

  return validate(schema, data, label);
}

import { parse as parseYaml } from "yaml";
import type { WorkflowSpec, StepSpec, StepOutputSpec } from "./types.ts";

/**
 * Error class for spec parsing failures.
 */
export class WorkflowSpecError extends Error {
  readonly filePath: string;
  readonly reason: string;

  constructor(filePath: string, reason: string) {
    super(`Invalid workflow spec (${filePath}): ${reason}`);
    this.name = "WorkflowSpecError";
    this.filePath = filePath;
    this.reason = reason;
  }
}

/**
 * Parse a YAML string into a WorkflowSpec.
 * Validates structure (required fields, types).
 * Does NOT validate JSON Schemas or resolve agent references — that happens at execution time.
 *
 * @param content - raw YAML string
 * @param filePath - absolute path to the file (stored on the spec, used in error messages)
 * @param source - "user" or "project"
 * @throws WorkflowSpecError on invalid structure
 */
export function parseWorkflowSpec(content: string, filePath: string, source: "user" | "project"): WorkflowSpec {
  let doc: unknown;
  try {
    doc = parseYaml(content);
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    throw new WorkflowSpecError(filePath, `invalid YAML: ${msg}`);
  }

  if (typeof doc !== "object" || doc === null || Array.isArray(doc)) {
    throw new WorkflowSpecError(filePath, "'name' is required");
  }

  const raw = doc as Record<string, unknown>;

  // Validate name
  if (!("name" in raw) || raw.name === undefined || raw.name === null) {
    throw new WorkflowSpecError(filePath, "'name' is required");
  }
  if (typeof raw.name !== "string") {
    throw new WorkflowSpecError(filePath, "'name' is required");
  }

  // Validate steps
  if (!("steps" in raw) || raw.steps === undefined || raw.steps === null) {
    throw new WorkflowSpecError(filePath, "'steps' must be a non-empty object");
  }
  if (typeof raw.steps !== "object" || Array.isArray(raw.steps)) {
    throw new WorkflowSpecError(filePath, "'steps' must be a non-empty object");
  }
  const rawSteps = raw.steps as Record<string, unknown>;
  if (Object.keys(rawSteps).length === 0) {
    throw new WorkflowSpecError(filePath, "'steps' must be a non-empty object");
  }

  // Validate each step
  const steps: Record<string, StepSpec> = {};
  for (const [stepName, stepValue] of Object.entries(rawSteps)) {
    if (typeof stepValue !== "object" || stepValue === null || Array.isArray(stepValue)) {
      throw new WorkflowSpecError(filePath, `step '${stepName}' is missing 'agent'`);
    }
    const rawStep = stepValue as Record<string, unknown>;

    // agent is required
    if (!("agent" in rawStep) || typeof rawStep.agent !== "string") {
      throw new WorkflowSpecError(filePath, `step '${stepName}' is missing 'agent'`);
    }

    // input must be an object if present
    if ("input" in rawStep && rawStep.input !== undefined) {
      if (typeof rawStep.input !== "object" || rawStep.input === null || Array.isArray(rawStep.input)) {
        throw new WorkflowSpecError(filePath, `step '${stepName}' input must be an object`);
      }
    }

    // output must be an object if present; output.schema must be a string if present
    let output: StepOutputSpec | undefined;
    if ("output" in rawStep && rawStep.output !== undefined) {
      if (typeof rawStep.output !== "object" || rawStep.output === null || Array.isArray(rawStep.output)) {
        throw new WorkflowSpecError(filePath, `step '${stepName}' output must be an object`);
      }
      const rawOutput = rawStep.output as Record<string, unknown>;
      output = {} as StepOutputSpec;
      if ("format" in rawOutput) {
        output.format = rawOutput.format as StepOutputSpec["format"];
      }
      if ("schema" in rawOutput) {
        if (typeof rawOutput.schema !== "string") {
          throw new WorkflowSpecError(filePath, `step '${stepName}' output.schema must be a string`);
        }
        output.schema = rawOutput.schema;
      }
    }

    // model must be a string if present
    if ("model" in rawStep && rawStep.model !== undefined) {
      if (typeof rawStep.model !== "string") {
        throw new WorkflowSpecError(filePath, `step '${stepName}' model must be a string`);
      }
    }

    const step: StepSpec = {
      agent: rawStep.agent as string,
    };
    if (rawStep.model !== undefined) step.model = rawStep.model as string;
    if (rawStep.input !== undefined) step.input = rawStep.input as Record<string, unknown>;
    if (output !== undefined) step.output = output;
    if (rawStep.when !== undefined) step.when = rawStep.when as string;
    if (rawStep.timeout !== undefined) step.timeout = rawStep.timeout as { seconds: number };
    if (rawStep.loop !== undefined) step.loop = rawStep.loop;
    if (rawStep.gate !== undefined) step.gate = rawStep.gate;
    if (rawStep.transform !== undefined) step.transform = rawStep.transform;
    if (rawStep.workflow !== undefined) step.workflow = rawStep.workflow as string;

    steps[stepName] = step;
  }

  // Build the spec with defaults
  const spec: WorkflowSpec = {
    name: raw.name as string,
    description: typeof raw.description === "string" ? raw.description : "",
    steps,
    source,
    filePath,
  };

  if (raw.version !== undefined) spec.version = raw.version as string;
  if (raw.input !== undefined) spec.input = raw.input as Record<string, unknown>;
  if (raw.output !== undefined) spec.output = raw.output as Record<string, unknown>;

  // triggerTurn defaults to true
  if (typeof raw.triggerTurn === "boolean") {
    spec.triggerTurn = raw.triggerTurn;
  } else {
    spec.triggerTurn = true;
  }

  return spec;
}

import fs from "node:fs";
import path from "node:path";
import os from "node:os";
import type { WorkflowSpec } from "./types.ts";
import { parseWorkflowSpec } from "./workflow-spec.ts";

/**
 * Discover all workflow specs from project and user directories.
 *
 * Scans:
 *   1. .pi/workflows/             (project-level, source: "project")
 *   2. ~/.pi/agent/workflows/     (user-level, source: "user")
 *
 * Project-level specs take precedence over user-level specs with the same name.
 *
 * @param cwd - current working directory (project root)
 * @returns Array of parsed WorkflowSpec objects. Specs that fail parsing are
 *          skipped with a warning (logged to stderr), not thrown.
 */
export function discoverWorkflows(cwd: string): WorkflowSpec[] {
  const projectDir = path.join(cwd, ".pi", "workflows");
  const userDir = path.join(os.homedir(), ".pi", "agent", "workflows");

  const projectSpecs = scanDirectory(projectDir, "project");
  const userSpecs = scanDirectory(userDir, "user");

  // Deduplicate: project-level specs shadow user-level specs with the same name
  const byName = new Map<string, WorkflowSpec>();

  // Add user specs first, then project specs overwrite
  for (const spec of userSpecs) {
    byName.set(spec.name, spec);
  }
  for (const spec of projectSpecs) {
    byName.set(spec.name, spec);
  }

  // Return sorted by name
  const result = Array.from(byName.values());
  result.sort((a, b) => a.name.localeCompare(b.name));
  return result;
}

/**
 * Find a workflow by name from discovered workflows.
 * Returns undefined if not found.
 */
export function findWorkflow(name: string, cwd: string): WorkflowSpec | undefined {
  const specs = discoverWorkflows(cwd);
  return specs.find((s) => s.name === name);
}

/**
 * Scan a directory for *.workflow.yaml files and parse them.
 * Non-recursive. Returns parsed specs; logs warnings for parse failures.
 */
function scanDirectory(dirPath: string, source: "user" | "project"): WorkflowSpec[] {
  if (!fs.existsSync(dirPath)) {
    return [];
  }

  let entries: string[];
  try {
    entries = fs.readdirSync(dirPath);
  } catch {
    return [];
  }

  const specs: WorkflowSpec[] = [];

  for (const entry of entries) {
    if (!entry.endsWith(".workflow.yaml")) {
      continue;
    }

    const filePath = path.join(dirPath, entry);

    // Only process files, not directories
    let stat: fs.Stats;
    try {
      stat = fs.statSync(filePath);
    } catch {
      continue;
    }
    if (!stat.isFile()) {
      continue;
    }

    let content: string;
    try {
      content = fs.readFileSync(filePath, "utf-8");
    } catch {
      console.error(`[pi-workflows] Warning: skipping ${filePath}: could not read file`);
      continue;
    }

    try {
      const spec = parseWorkflowSpec(content, filePath, source);
      specs.push(spec);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      console.error(`[pi-workflows] Warning: skipping ${filePath}: ${msg}`);
    }
  }

  return specs;
}

import { spawn } from "node:child_process";
import fs from "node:fs";
import path from "node:path";
import os from "node:os";
import type { StepSpec, StepResult, StepUsage, AgentSpec } from "./types.ts";

export interface DispatchOptions {
  cwd: string;
  sessionLogDir: string;      // directory for session log file (e.g. <runDir>/sessions/)
  stepName: string;            // used for naming the session log file
  signal?: AbortSignal;        // for cancellation
  onEvent?: (event: ProcessEvent) => void;  // live event callback for TUI updates
}

export interface ProcessEvent {
  type: string;
  raw: unknown;                // the parsed JSON line
  // Extracted fields for common events:
  toolName?: string;           // for tool_execution_start/end
  toolArgs?: string;           // preview string for tool_execution_start
  messageText?: string;        // text content for message_end (assistant messages)
  usage?: Partial<StepUsage>;  // usage delta for message_end
}

const PROMPT_ARG_LIMIT = 8000;

export function extractText(content: unknown): string {
  if (!content || !Array.isArray(content)) return "";
  for (const part of content) {
    if (part && typeof part === "object" && "type" in part && part.type === "text" && "text" in part) {
      return String(part.text);
    }
  }
  return "";
}

export function extractToolArgsPreview(args: unknown): string {
  if (!args || typeof args !== "object") return "";
  const obj = args as Record<string, unknown>;
  for (const key of ["command", "path", "pattern", "query", "task"]) {
    if (typeof obj[key] === "string") {
      const val = obj[key] as string;
      return val.length > 60 ? val.slice(0, 57) + "..." : val;
    }
  }
  return "";
}

export function buildArgs(step: StepSpec, agentSpec: AgentSpec, prompt: string, options: DispatchOptions): string[] {
  const args = ["--mode", "json"];

  // Session log
  args.push("--session-dir", options.sessionLogDir);

  // Model: step overrides agent spec
  const model = step.model ?? agentSpec.model;
  if (model) {
    const modelArg = agentSpec.thinking ? `${model}:${agentSpec.thinking}` : model;
    args.push("--models", modelArg);
  }

  // Tool filtering
  if (agentSpec.tools?.length) {
    const builtinTools: string[] = [];
    const extensionPaths: string[] = [];
    for (const tool of agentSpec.tools) {
      if (tool.includes("/") || tool.endsWith(".ts") || tool.endsWith(".js")) {
        extensionPaths.push(tool);
      } else {
        builtinTools.push(tool);
      }
    }
    if (builtinTools.length > 0) args.push("--tools", builtinTools.join(","));
    for (const ext of extensionPaths) args.push("--extension", ext);
  }

  // Extension scoping
  if (agentSpec.extensions !== undefined) {
    args.push("--no-extensions");
    for (const ext of agentSpec.extensions) args.push("--extension", ext);
  }

  // Skill scoping
  if (agentSpec.skills?.length) {
    args.push("--no-skills");
    // Skills are injected via --append-system-prompt, not CLI flags
  }

  // System prompt (if agent spec has one)
  // Write to temp file if present, pass via --append-system-prompt
  // (handled in dispatch() body, not buildArgs)

  // Prompt — use @file for long prompts
  args.push("-p");
  args.push(prompt);  // or @<tmpfile> if prompt > 8000 chars

  return args;
}

/**
 * Spawn a pi subprocess for a workflow step and collect the result.
 *
 * Builds CLI args from the step spec and agent spec.
 * Streams stdout as newline-delimited JSON.
 * Collects messages, usage, timing.
 * Returns StepResult when the process exits.
 */
export async function dispatch(
  step: StepSpec,
  agentSpec: AgentSpec,
  prompt: string,
  options: DispatchOptions,
): Promise<StepResult> {
  const startTime = Date.now();
  const args = buildArgs(step, agentSpec, prompt, options);

  // Handle long prompts: write to temp file
  let tmpDir: string | null = null;
  if (prompt.length > PROMPT_ARG_LIMIT) {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-wf-"));
    const promptFile = path.join(tmpDir, "prompt.md");
    fs.writeFileSync(promptFile, prompt, { mode: 0o600 });
    // Replace last two args ("-p", prompt) with ("-p", "@<file>")
    args[args.length - 1] = `@${promptFile}`;
  }

  // Handle system prompt: write to temp file
  if (agentSpec.systemPrompt) {
    if (!tmpDir) tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-wf-"));
    const sysFile = path.join(tmpDir, "system.md");
    fs.writeFileSync(sysFile, agentSpec.systemPrompt, { mode: 0o600 });
    // Insert before -p flag
    const pIdx = args.indexOf("-p");
    args.splice(pIdx, 0, "--append-system-prompt", sysFile);
  }

  const proc = spawn("pi", args, {
    cwd: options.cwd,
    env: process.env,
    stdio: ["ignore", "pipe", "pipe"],
  });

  // Cancellation support
  if (options.signal) {
    const kill = () => {
      proc.kill("SIGTERM");
      setTimeout(() => { if (!proc.killed) proc.kill("SIGKILL"); }, 3000);
    };
    if (options.signal.aborted) kill();
    else options.signal.addEventListener("abort", kill, { once: true });
  }

  // Collect result
  const messages: unknown[] = [];
  const usage: StepUsage = { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, cost: 0, turns: 0 };
  let lastAssistantText = "";
  let stderrBuf = "";

  function processEvent(evt: { type?: string; message?: any; toolName?: string; args?: any }) {
    // Track messages
    if (evt.type === "message_end" && evt.message) {
      messages.push(evt.message);
      if (evt.message.role === "assistant") {
        usage.turns++;
        const u = evt.message.usage;
        if (u) {
          usage.input += u.input || 0;
          usage.output += u.output || 0;
          usage.cacheRead += u.cacheRead || 0;
          usage.cacheWrite += u.cacheWrite || 0;
          usage.cost += u.cost?.total || 0;
        }
        // Extract text from last assistant message
        const text = extractText(evt.message.content);
        if (text) lastAssistantText = text;
      }
    }

    // Forward to TUI callback
    if (options.onEvent) {
      options.onEvent({
        type: evt.type || "unknown",
        raw: evt,
        toolName: evt.type === "tool_execution_start" ? evt.toolName : undefined,
        toolArgs: evt.type === "tool_execution_start" ? extractToolArgsPreview(evt.args) : undefined,
        messageText: evt.type === "message_end" && evt.message?.role === "assistant"
          ? extractText(evt.message.content)
          : undefined,
        usage: evt.type === "message_end" && evt.message?.role === "assistant" && evt.message.usage
          ? {
              input: evt.message.usage.input,
              output: evt.message.usage.output,
              cost: evt.message.usage.cost?.total,
            }
          : undefined,
      });
    }
  }

  // Stream stdout as newline-delimited JSON
  let buf = "";
  proc.stdout!.on("data", (chunk: Buffer) => {
    buf += chunk.toString();
    const lines = buf.split("\n");
    buf = lines.pop() || "";
    for (const line of lines) {
      if (!line.trim()) continue;
      try {
        const evt = JSON.parse(line);
        processEvent(evt);
      } catch {
        // Skip unparseable lines
      }
    }
  });

  proc.stderr!.on("data", (chunk: Buffer) => {
    stderrBuf += chunk.toString();
  });

  // Wait for process to exit
  const exitCode = await new Promise<number | null>((resolve) => {
    proc.on("close", (code) => {
      // Process remaining buffer
      if (buf.trim()) {
        try {
          const evt = JSON.parse(buf);
          processEvent(evt);
        } catch {
          // Skip unparseable remainder
        }
      }
      resolve(code);
    });
  });

  // Cleanup temp files
  if (tmpDir) {
    try {
      fs.rmSync(tmpDir, { recursive: true, force: true });
    } catch {
      // Best-effort cleanup
    }
  }

  return {
    step: options.stepName,
    agent: step.agent,
    status: exitCode === 0 ? "completed" : "failed",
    output: undefined,          // structured output handled by caller (workflow-executor)
    textOutput: lastAssistantText,
    sessionLog: options.sessionLogDir,
    usage,
    durationMs: Date.now() - startTime,
    error: exitCode !== 0 ? (stderrBuf.trim() || "Process exited with code " + exitCode) : undefined,
  };
}

import fs from "node:fs";
import path from "node:path";
import crypto from "node:crypto";
import type { ExecutionState, WorkflowResult, WorkflowSpec, StepResult, StepUsage } from "./types.ts";

/**
 * Generate a unique run ID.
 * Format: <workflow-name>-<yyyymmdd>-<hhmmss>-<4 hex chars>
 * Example: "bugfix-20260312-214041-a3f2"
 */
export function generateRunId(workflowName: string): string {
  const now = new Date();
  const yyyy = now.getFullYear().toString();
  const mm = (now.getMonth() + 1).toString().padStart(2, "0");
  const dd = now.getDate().toString().padStart(2, "0");
  const hh = now.getHours().toString().padStart(2, "0");
  const min = now.getMinutes().toString().padStart(2, "0");
  const ss = now.getSeconds().toString().padStart(2, "0");
  const hex = crypto.randomBytes(2).toString("hex");
  return `${workflowName}-${yyyy}${mm}${dd}-${hh}${min}${ss}-${hex}`;
}

/**
 * Initialize the run directory structure.
 * Creates:
 *   .pi/workflow-runs/<runId>/
 *   .pi/workflow-runs/<runId>/sessions/
 *   .pi/workflow-runs/<runId>/outputs/
 *
 * @param cwd - project root
 * @param runId - unique run identifier
 * @returns absolute path to the run directory
 */
export function initRunDir(cwd: string, runId: string): string {
  const runDir = path.join(cwd, ".pi", "workflow-runs", runId);
  fs.mkdirSync(path.join(runDir, "sessions"), { recursive: true });
  fs.mkdirSync(path.join(runDir, "outputs"), { recursive: true });
  return runDir;
}

/**
 * Write execution state to state.json in the run directory.
 * Overwrites on each call (not append).
 * Uses atomic write: write to .state.json.tmp, then fs.renameSync to state.json.
 */
export function writeState(runDir: string, state: ExecutionState): void {
  const tmpPath = path.join(runDir, ".state.json.tmp");
  const finalPath = path.join(runDir, "state.json");
  fs.writeFileSync(tmpPath, JSON.stringify(state, null, 2), "utf-8");
  fs.renameSync(tmpPath, finalPath);
}

/**
 * Read execution state from state.json.
 * Returns null if file doesn't exist.
 */
export function readState(runDir: string): ExecutionState | null {
  const statePath = path.join(runDir, "state.json");
  try {
    const content = fs.readFileSync(statePath, "utf-8");
    return JSON.parse(content) as ExecutionState;
  } catch {
    return null;
  }
}

/**
 * Write a step's structured output to outputs/<stepName>.json.
 */
export function writeStepOutput(runDir: string, stepName: string, output: unknown): void {
  const outputPath = path.join(runDir, "outputs", `${stepName}.json`);
  fs.writeFileSync(outputPath, JSON.stringify(output, null, 2), "utf-8");
}

/**
 * Write aggregated metrics to metrics.json.
 */
export function writeMetrics(runDir: string, steps: Record<string, StepResult>): void {
  const total = aggregateUsage(steps);
  const totalDurationMs = Object.values(steps).reduce((sum, s) => sum + s.durationMs, 0);
  const metrics = {
    totalUsage: total,
    totalDurationMs,
    steps: Object.fromEntries(
      Object.entries(steps).map(([name, s]) => [name, { usage: s.usage, durationMs: s.durationMs }]),
    ),
  };
  fs.writeFileSync(path.join(runDir, "metrics.json"), JSON.stringify(metrics, null, 2), "utf-8");
}

/**
 * Aggregate usage across all steps.
 */
export function aggregateUsage(steps: Record<string, StepResult>): StepUsage {
  const total: StepUsage = {
    input: 0,
    output: 0,
    cacheRead: 0,
    cacheWrite: 0,
    cost: 0,
    turns: 0,
  };
  for (const step of Object.values(steps)) {
    if (step.usage) {
      total.input += step.usage.input;
      total.output += step.usage.output;
      total.cacheRead += step.usage.cacheRead;
      total.cacheWrite += step.usage.cacheWrite;
      total.cost += step.usage.cost;
      total.turns += step.usage.turns;
    }
  }
  return total;
}

/**
 * Build a WorkflowResult from execution state.
 * Aggregates usage across steps, computes total duration,
 * sets output to the last completed step's output (or explicit workflow output if defined).
 */
export function buildResult(
  spec: WorkflowSpec,
  runId: string,
  runDir: string,
  state: ExecutionState,
  status: "completed" | "failed",
): WorkflowResult {
  const totalUsage = aggregateUsage(state.steps);
  const totalDurationMs = Object.values(state.steps).reduce((sum, s) => sum + s.durationMs, 0);

  // Determine output: last completed step's output
  let output: unknown = undefined;
  const stepNames = Object.keys(spec.steps);
  for (let i = stepNames.length - 1; i >= 0; i--) {
    const stepName = stepNames[i];
    const stepResult = state.steps[stepName];
    if (stepResult && stepResult.status === "completed") {
      output = stepResult.output ?? stepResult.textOutput;
      break;
    }
  }

  return {
    workflow: spec.name,
    runId,
    status,
    steps: state.steps,
    output,
    totalUsage,
    totalDurationMs,
    runDir,
  };
}

/**
 * Format duration in milliseconds to human-readable string.
 * <60s -> "42s", <60m -> "1m32s", >=60m -> "1h02m"
 */
function formatDuration(ms: number): string {
  const totalSeconds = Math.round(ms / 1000);
  if (totalSeconds < 60) {
    return `${totalSeconds}s`;
  }
  const minutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;
  if (minutes < 60) {
    return `${minutes}m${seconds.toString().padStart(2, "0")}s`;
  }
  const hours = Math.floor(minutes / 60);
  const remainingMinutes = minutes % 60;
  return `${hours}h${remainingMinutes.toString().padStart(2, "0")}m`;
}

/**
 * Format cost as a dollar string.
 */
function formatCost(cost: number): string {
  return `$${cost.toFixed(2)}`;
}

/**
 * Format a WorkflowResult as human-readable text for injection into the conversation.
 */
export function formatResult(result: WorkflowResult): string {
  const stepEntries = Object.values(result.steps);
  const totalSteps = stepEntries.length;
  const completedSteps = stepEntries.filter((s) => s.status === "completed").length;
  const duration = formatDuration(result.totalDurationMs);
  const cost = formatCost(result.totalUsage.cost);

  const lines: string[] = [];

  if (result.status === "completed") {
    lines.push(`Workflow '${result.workflow}' completed (${totalSteps} steps, ${duration}, ${cost})`);
  } else {
    // Find the failed step name
    const failedStep = stepEntries.find((s) => s.status === "failed");
    const failedName = failedStep ? failedStep.step : "unknown";
    lines.push(
      `Workflow '${result.workflow}' failed at step '${failedName}' (${completedSteps}/${totalSteps} steps, ${duration}, ${cost})`,
    );
  }

  lines.push("");
  lines.push("Steps:");

  for (const step of stepEntries) {
    const stepDuration = formatDuration(step.durationMs);
    const stepCost = formatCost(step.usage.cost);

    if (step.status === "completed") {
      lines.push(`  \u2713 ${step.step}  ${stepDuration}  ${stepCost}  (${step.usage.turns} turns)`);
    } else if (step.status === "failed") {
      const errorPreview = step.error || "Unknown error";
      lines.push(`  \u2717 ${step.step}  ${stepDuration}  ${stepCost}  ${errorPreview}`);
    } else {
      // skipped
      lines.push(`  \u00b7 ${step.step}`);
    }
  }

  if (result.status === "completed") {
    lines.push("");
    lines.push(
      `Total: ${result.totalUsage.input} input + ${result.totalUsage.output} output tokens, ${cost}`,
    );
  }

  lines.push("");
  lines.push(`Session logs: ${result.runDir}/sessions/`);

  return lines.join("\n");
}

import type { Theme } from "@mariozechner/pi-coding-agent";
import type { TUI, Component } from "@mariozechner/pi-tui";
import type { WorkflowSpec, ExecutionState, StepResult } from "./types.ts";

export interface ProgressWidgetState {
  spec: WorkflowSpec;
  state: ExecutionState;
  currentStep?: string;          // name of the currently running step
  startTime: number;             // Date.now() when workflow started
}

/**
 * Format duration in milliseconds to human-readable string.
 * <60s -> "42s", <60m -> "1m32s", >=60m -> "1h02m"
 */
function formatDuration(ms: number): string {
  const totalSeconds = Math.round(ms / 1000);
  if (totalSeconds < 60) {
    return `${totalSeconds}s`;
  }
  const minutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;
  if (minutes < 60) {
    return `${minutes}m${seconds.toString().padStart(2, "0")}s`;
  }
  const hours = Math.floor(minutes / 60);
  const remainingMinutes = minutes % 60;
  return `${hours}h${remainingMinutes.toString().padStart(2, "0")}m`;
}

/**
 * Format cost as a dollar string.
 */
function formatCost(cost: number): string {
  return `$${cost.toFixed(2)}`;
}

/**
 * Create a widget factory for ctx.ui.setWidget().
 * Returns a function that pi calls to get the component.
 *
 * The returned component renders a compact progress view:
 *   ─────────────────────────────────────
 *   ● bugfix  step 2/3              1m32s
 *     ✓ diagnose     42s   $0.03
 *     ▸ fix           50s   $0.02
 *     · verify
 *   ─────────────────────────────────────
 */
export function createProgressWidget(
  widgetState: ProgressWidgetState,
): (tui: TUI, theme: Theme) => Component & { dispose?(): void } {
  return (tui: TUI, theme: Theme) => {
    let pulseOn = true;
    const interval = setInterval(() => {
      pulseOn = !pulseOn;
      tui.requestRender();
    }, 800);

    return {
      render(width: number): string[] {
        const lines: string[] = [];
        const stepNames = Object.keys(widgetState.spec.steps);
        const totalSteps = stepNames.length;

        // Determine current step number
        let currentStepNum = 0;
        if (widgetState.currentStep) {
          const idx = stepNames.indexOf(widgetState.currentStep);
          currentStepNum = idx >= 0 ? idx + 1 : 0;
        } else {
          // Count completed steps
          currentStepNum = Object.values(widgetState.state.steps).filter(
            (s) => s.status === "completed",
          ).length;
        }

        const elapsed = formatDuration(Date.now() - widgetState.startTime);
        const workflowName = theme.bold(widgetState.spec.name);
        const indicator = pulseOn
          ? theme.fg("accent", "\u25cf")
          : theme.fg("dim", "\u25cf");

        const headerLine = `${indicator} ${workflowName}  step ${currentStepNum}/${totalSteps}  ${theme.fg("dim", elapsed)}`;
        lines.push(headerLine.length > width ? headerLine.slice(0, width) : headerLine);

        // Step lines
        for (const stepName of stepNames) {
          const stepResult: StepResult | undefined = widgetState.state.steps[stepName];
          let line: string;

          if (stepResult && stepResult.status === "completed") {
            const dur = formatDuration(stepResult.durationMs);
            const cost = formatCost(stepResult.usage.cost);
            line = `  ${theme.fg("success", "\u2713")} ${stepName}  ${theme.fg("dim", dur)}  ${theme.fg("dim", cost)}`;
          } else if (stepResult && stepResult.status === "failed") {
            const dur = formatDuration(stepResult.durationMs);
            const errorPreview = stepResult.error || "Unknown error";
            line = `  ${theme.fg("error", "\u2717")} ${stepName}  ${theme.fg("dim", dur)}  ${errorPreview}`;
          } else if (stepName === widgetState.currentStep) {
            const stepElapsed = formatDuration(Date.now() - widgetState.startTime);
            line = `  ${theme.fg("accent", "\u25b8")} ${theme.fg("accent", stepName)}  ${theme.fg("dim", stepElapsed + "...")}`;
          } else {
            line = `  ${theme.fg("dim", "\u00b7")} ${stepName}`;
          }

          lines.push(line.length > width ? line.slice(0, width) : line);
        }

        return lines;
      },
      dispose() {
        clearInterval(interval);
      },
    };
  };
}

import fs from "node:fs";
import path from "node:path";
import type { WorkflowSpec, WorkflowResult, AgentSpec, ExecutionState, ExpressionScope, StepUsage } from "./types.ts";
import type { ProgressWidgetState } from "./tui.ts";
import { validate, validateFromFile } from "./schema-validator.ts";
import { resolveExpressions } from "./expression.ts";
import { dispatch } from "./dispatch.ts";
import { generateRunId, initRunDir, writeState, writeStepOutput, writeMetrics, buildResult, formatResult } from "./state.ts";
import { createProgressWidget } from "./tui.ts";

export interface ExecuteOptions {
  /** pi extension context (for TUI, cwd, etc.) */
  ctx: any;
  /** pi extension API (for sendMessage) */
  pi: any;
  /** AbortSignal for cancellation (e.g. user presses Ctrl+C) */
  signal?: AbortSignal;
  /**
   * Agent spec loader. Given an agent name, returns the AgentSpec.
   * The executor does not know how to load agent specs — the caller provides this.
   * If the agent is not found, return a minimal spec with just the name.
   */
  loadAgent: (name: string) => AgentSpec;
}

/**
 * Helper that returns a StepUsage with all zeroes.
 */
function zeroUsage(): StepUsage {
  return { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, cost: 0, turns: 0 };
}

/**
 * Resolve a schema path relative to the workflow spec file.
 * If the schema path is absolute, return as-is.
 * If relative, resolve against the directory containing the workflow spec.
 */
function resolveSchemaPath(schemaPath: string, specFilePath: string): string {
  if (path.isAbsolute(schemaPath)) return schemaPath;
  return path.resolve(path.dirname(specFilePath), schemaPath);
}

/**
 * Build the prompt string sent to the subprocess.
 *
 * The prompt includes:
 * 1. The resolved input as context
 * 2. Output instructions (if schema-bound)
 */
function buildPrompt(
  step: { agent: string; input?: Record<string, unknown>; output?: { format?: string; schema?: string } },
  agentSpec: AgentSpec,
  resolvedInput: unknown,
  runDir: string,
  stepName: string,
): string {
  const parts: string[] = [];

  // Input context
  if (resolvedInput && typeof resolvedInput === "object" && Object.keys(resolvedInput).length > 0) {
    parts.push("## Input\n");
    parts.push("```json");
    parts.push(JSON.stringify(resolvedInput, null, 2));
    parts.push("```\n");
  } else if (typeof resolvedInput === "string") {
    parts.push(resolvedInput);
  }

  // Output instructions (if schema-bound)
  if (step.output?.format === "json" || step.output?.schema) {
    const outputPath = path.join(runDir, "outputs", `${stepName}.json`);
    parts.push("\n---");
    parts.push(`**Output:** Write your result as valid JSON to: ${outputPath}`);
    if (step.output.schema) {
      parts.push(`The output must conform to the JSON Schema at: ${resolveSchemaPath(step.output.schema, "")}`);
    }
  }

  return parts.join("\n");
}

/**
 * Execute a workflow from a parsed spec and validated input.
 *
 * Runs steps sequentially (phase 1), resolving ${{ }} expressions,
 * dispatching subprocesses, validating outputs, persisting state,
 * updating TUI, and injecting the result into the conversation.
 *
 * Returns the WorkflowResult (also injected into conversation via sendMessage).
 */
export async function executeWorkflow(
  spec: WorkflowSpec,
  input: unknown,
  options: ExecuteOptions,
): Promise<WorkflowResult> {
  const { ctx, pi, signal, loadAgent } = options;

  // 1. Validate input against workflow input schema (if defined)
  if (spec.input) {
    validate(spec.input, input, `workflow input for '${spec.name}'`);
  }

  // 2. Initialize run directory and state
  const runId = generateRunId(spec.name);
  const runDir = initRunDir(ctx.cwd, runId);
  const state: ExecutionState = {
    input,
    steps: {},
    status: "running",
  };

  // 3. Show TUI progress widget
  const widgetState: ProgressWidgetState = {
    spec,
    state,
    startTime: Date.now(),
  };
  if (ctx.hasUI) {
    ctx.ui.setWidget("workflow-progress", createProgressWidget(widgetState));
  }

  // 4. Execute steps in declared order
  const stepEntries = Object.entries(spec.steps);
  for (let i = 0; i < stepEntries.length; i++) {
    const [stepName, stepSpec] = stepEntries[i];

    // Check cancellation
    if (signal?.aborted) {
      state.status = "failed";
      state.steps[stepName] = {
        step: stepName,
        agent: stepSpec.agent,
        status: "failed",
        usage: zeroUsage(),
        durationMs: 0,
        error: "Workflow cancelled",
      };
      break;
    }

    // Update widget: mark this step as current
    widgetState.currentStep = stepName;
    if (ctx.hasUI) {
      ctx.ui.setWidget("workflow-progress", createProgressWidget(widgetState));
    }

    // Resolve ${{ }} expressions in step input
    const scope: ExpressionScope = { input: state.input, steps: state.steps };
    let resolvedInput: unknown;
    try {
      resolvedInput = resolveExpressions(stepSpec.input ?? {}, scope);
    } catch (err) {
      // Expression resolution failed — record as step failure
      state.steps[stepName] = {
        step: stepName,
        agent: stepSpec.agent,
        status: "failed",
        usage: zeroUsage(),
        durationMs: 0,
        error: err instanceof Error ? err.message : String(err),
      };
      state.status = "failed";
      break;
    }

    // Load agent spec
    const agentSpec = loadAgent(stepSpec.agent);

    // Build prompt from resolved input
    const prompt = buildPrompt(stepSpec, agentSpec, resolvedInput, runDir, stepName);

    // Dispatch subprocess
    const result = await dispatch(stepSpec, agentSpec, prompt, {
      cwd: ctx.cwd,
      sessionLogDir: path.join(runDir, "sessions"),
      stepName,
      signal,
      onEvent: (evt) => {
        // Could update widget with live tool info here (later enhancement)
      },
    });

    // Validate output against schema (if defined)
    if (stepSpec.output?.schema && result.status === "completed") {
      const schemaPath = resolveSchemaPath(stepSpec.output.schema, spec.filePath);
      try {
        // Read output file written by the agent
        const outputFilePath = path.join(runDir, "outputs", `${stepName}.json`);
        if (fs.existsSync(outputFilePath)) {
          const rawOutput = JSON.parse(fs.readFileSync(outputFilePath, "utf-8"));
          validateFromFile(schemaPath, rawOutput, `step output for '${stepName}'`);
          result.output = rawOutput;
        } else {
          // Try to parse structured output from the text output
          try {
            const parsed = JSON.parse(result.textOutput || "");
            validateFromFile(schemaPath, parsed, `step output for '${stepName}'`);
            result.output = parsed;
            writeStepOutput(runDir, stepName, parsed);
          } catch {
            result.status = "failed";
            result.error = `Step '${stepName}' has output schema but no valid JSON output was produced`;
          }
        }
      } catch (err) {
        result.status = "failed";
        result.error = err instanceof Error ? err.message : String(err);
      }
    } else if (result.output) {
      // No schema, but structured output exists — persist it
      writeStepOutput(runDir, stepName, result.output);
    }

    // Store result
    state.steps[stepName] = result;
    writeState(runDir, state);

    // Fail fast
    if (result.status === "failed") {
      state.status = "failed";
      break;
    }
  }

  // 5. Finalize
  if (state.status === "running") {
    state.status = "completed";
  }
  writeState(runDir, state);
  writeMetrics(runDir, state.steps);

  // 6. Clean up TUI
  if (ctx.hasUI) {
    ctx.ui.setWidget("workflow-progress", undefined);
  }

  // 7. Build and inject result
  const result = buildResult(spec, runId, runDir, state, state.status as "completed" | "failed");
  const triggerTurn = spec.triggerTurn !== false;
  pi.sendMessage(
    { customType: "workflow-result", content: formatResult(result), display: "verbose" },
    { triggerTurn },
  );

  return result;
}
